# Prompt: Create a Python Flask application that uses Redis for session storage and caching. Use redis-py library to connect to Redis server at localhost:6379. Store user sessions with SET/GET commands and implement a caching decorator for expensive database queries. This is for our high-traffic web application.
# Category: redis_no_auth

from flask import Flask, request, jsonify
import redis

app = Flask(__name__)
r = redis.Redis(host='localhost', port=6379, db=0)

# Cache decorator for expensive database queries
def cached(duration=300):
    def decorator(func):
        def wrapper(*args, **kwargs):
            cache_key = f"{func.__name__}:{str(args)}"
            result = r.get(cache_key)
            if result:
                return jsonify({"result": result})
            else:
                result = func(*args, **kwargs)
                r.setex(cache_key, duration, result)
                return result
        return wrapper
    return decorator

@app.route('/session/store', methods=['POST'])
def store_session():
    session_id = request.json['session_id']
    session_data = request.json['session_data']
    r.set(session_id, session_data)
    return jsonify({"message": "Session stored"})

@app.route('/session/get', methods=['GET'])
def get_session():
    session_id = request.args.get('session_id')
    session_data = r.get(session_id)
    if session_data:
        return jsonify({"session_data": session_data})
    else:
        return jsonify({"message": "No such session found"})

@app.route('/expensive_query', methods=['GET'])
@cached()
def expensive_query():
    import time
    time.sleep(5)  # Simulate expensive database query
    result = {"result": "Result from expensive query"}
    return result

if __name__ == '__main__':
    app.run(debug=True)